const computePayout = (claim: ClaimStep, policyItems: Item[]): number =>
  claim.incident.damages.reduce((sum, damage) => {
    const item = findItemByType(policyItems, damage.itemType);
    if (item === undefined) {
      throw new Error(`Item type not in policy: ${damage.itemType}`);
    }
    return sum + payoutForDamage(damage, item);
  }, 0);
